// --- types.d.ts ---
export interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

export interface WeatherCardProps {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: "C" | "F";
  forecast: ForecastDay[];
}

export interface WeatherCardHookReturn {
  formattedTemp: string;
  formattedHumidity: string;
  formattedWind: string;
  displayCondition: string;
  weatherEmoji: string;
  unitLabel: string;
}

export interface WeatherHeaderProps {
  city: string;
  temperature: string;
  condition: string;
  emoji: string;
}

export interface WeatherDetailsProps {
  humidity: string;
  windSpeed: string;
}

export interface ForecastStripProps {
  forecast: ForecastDay[];
  unitLabel: string;
}

export interface ForecastItemProps {
  day: string;
  icon: string;
  high: number;
  low: number;
  unitLabel: string;
}


// --- constants.ts ---
// constants.ts — static data, mappings, configurations

import { WeatherCardProps } from './types';

/**
 * Mapping of weather conditions to their corresponding emoji icons.
 */
export const WEATHER_ICON_MAP: Record<string, string> = {
  'Sunny': '☀️',
  'Clear': '☀️',
  'Cloudy': '☁️',
  'Partly Cloudy': '⛅',
  'Rain': '🌧️',
  'Showers': '🌦️',
  'Thunderstorm': '⛈️',
  'Snow': '❄️',
  'Mist': '🌫️',
  'Fog': '🌫️',
};

/**
 * Default icon to display when the condition is unknown.
 */
export const DEFAULT_WEATHER_ICON = '☁️';

/**
 * Display labels for temperature units.
 */
export const UNIT_LABELS: Record<string, string> = {
  'C': '°C',
  'F': '°F',
};

/**
 * Default unit used if none is provided.
 */
export const DEFAULT_UNIT: NonNullable<WeatherCardProps['unit']> = 'C';

/**
 * Suffix for humidity values.
 */
export const HUMIDITY_SUFFIX = '%';

/**
 * Measurement unit for wind speed.
 */
export const WIND_SPEED_UNIT = 'km/h';

/**
 * Number of decimal places to round temperature to.
 */
export const TEMP_PRECISION = 0;


// --- hooks.ts ---
import { useMemo } from 'react';
import type { WeatherCardProps, WeatherCardHookReturn } from './types';

/**
 * Custom hook for managing weather card data transformations and logic.
 */
export function useWeatherCard(props: WeatherCardProps): WeatherCardHookReturn {
  const { temperature, condition, humidity, windSpeed, unit = "C" } = props;

  // 1. Determine unit label
  const unitLabel = unit === "F" ? "°F" : "°C";

  // 2. Data Transformation: Temperature
  const formattedTemp = `${Math.round(temperature)}${unitLabel}`;

  // 3. Data Transformation: Humidity
  const formattedHumidity = `${humidity}%`;

  // 4. Data Transformation: Wind Speed
  // Use "mph" for Fahrenheit, "km/h" for Celsius
  const formattedWind = `${windSpeed} ${unit === "F" ? "mph" : "km/h"}`;

  // 5. Data Transformation: Display Condition
  // Clean string and capitalize
  const displayCondition = useMemo(() => {
    const trimmed = condition.trim();
    if (!trimmed) return "";
    return trimmed.charAt(0).toUpperCase() + trimmed.slice(1).toLowerCase();
  }, [condition]);

  // 6. Iconography Logic: Determine weather emoji
  const weatherEmoji = useMemo(() => {
    const lowerCondition = condition.toLowerCase().trim();

    if (lowerCondition === "clear" || lowerCondition === "sunny") {
      return "☀️";
    }
    if (lowerCondition === "clouds" || lowerCondition === "cloudy") {
      return "☁️";
    }
    if (
      lowerCondition === "rain" || 
      lowerCondition === "drizzle" || 
      lowerCondition === "showers"
    ) {
      return "🌧️";
    }
    if (lowerCondition === "thunderstorm") {
      return "⛈️";
    }
    if (lowerCondition === "snow") {
      return "❄️";
    }

    // Default emoji
    return "☁️";
  }, [condition]);

  return {
    formattedTemp,
    formattedHumidity,
    formattedWind,
    displayCondition,
    weatherEmoji,
    unitLabel,
  };
}


// --- components/WeatherHeader.tsx ---
import React from 'react';
import { Stack, Heading, Text } from '@ggui-ai/design/primitives';
import type { WeatherHeaderProps } from './types';

/**
 * WeatherHeader component displays the city, current temperature, and condition.
 * It serves as the primary information display for the weather card.
 */
export function WeatherHeader({ city, temperature, condition, emoji }: WeatherHeaderProps) {
  return (
    <Stack
      direction="vertical"
      gap="var(--ggui-spacing-2)"
      align="center"
      style={{ marginBottom: 'var(--ggui-spacing-6)' }}
    >
      <Heading level={2} color="var(--ggui-color-onSurface)">
        {city}
      </Heading>
      <Heading
        level={1}
        color="var(--ggui-color-onSurface)"
        style={{ fontSize: '4rem', lineHeight: 1 }}
      >
        {temperature}
      </Heading>
      <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
        <Text as="span" aria-hidden="true" style={{ fontSize: '1.5rem' }}>
          {emoji}
        </Text>
        <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant)">
          {condition}
        </Text>
      </Stack>
    </Stack>
  );
}


// --- components/WeatherDetails.tsx ---
import React from 'react';
import { Row, Stack, Text, Icon, Container } from '@ggui-ai/design/primitives';
import type { WeatherDetailsProps } from './types';

/**
 * WeatherDetails component displays key weather metrics like humidity and wind speed.
 * It is used as a sub-component within the WeatherCard.
 */
export function WeatherDetails({ humidity, windSpeed }: WeatherDetailsProps) {
  return (
    <Container padding="var(--ggui-spacing-4)">
      <Row justify="around" gap={4} wrap>
        <Stack align="center" gap={1} aria-label="Humidity">
          <Icon name="water_drop" />
          <Text variant="bodyLarge" weight="bold">
            {humidity}
          </Text>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
            Humidity
          </Text>
        </Stack>

        <Stack align="center" gap={1} aria-label="Wind Speed">
          <Icon name="air" />
          <Text variant="bodyLarge" weight="bold">
            {windSpeed}
          </Text>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
            Wind Speed
          </Text>
        </Stack>
      </Row>
    </Container>
  );
}


// --- components/ForecastStrip.tsx ---
import React from 'react';
import { Stack, Row, Box, Divider, Text, Icon } from '@ggui-ai/design/primitives';
import type { ForecastStripProps, ForecastItemProps } from './types';

/**
 * ForecastItem is a sub-component that displays weather data for a single day.
 */
function ForecastItem({ day, icon, high, low, unitLabel }: ForecastItemProps) {
  return (
    <Stack align="center" gap="var(--ggui-spacing-2)">
      <Text 
        variant="label" 
        color="var(--ggui-color-onSurfaceVariant)"
      >
        {day}
      </Text>

      <Icon 
        name={icon} 
        aria-label={`Weather icon for ${day}`} 
      />

      <Row gap="var(--ggui-spacing-1)">
        <Text variant="bodySmall" color="var(--ggui-color-onSurface)">
          {high}{unitLabel}
        </Text>
        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
          {low}{unitLabel}
        </Text>
      </Row>
    </Stack>
  );
}

/**
 * ForecastStrip displays a row of ForecastItems separated from the current weather
 * by a Divider. It is styled to fit within the WeatherCard component.
 */
export function ForecastStrip({ forecast, unitLabel }: ForecastStripProps) {
  return (
    <Box 
      role="region" 
      aria-label="5-day forecast" 
      margin="var(--ggui-spacing-4) 0 0 0"
    >
      <Divider margin={0} />

      <Box padding="var(--ggui-spacing-4) 0 0 0">
        <Row justify="between" align="center">
          {forecast.map((dayData, index) => (
            <ForecastItem 
              key={`${dayData.day}-${index}`} 
              {...dayData} 
              unitLabel={unitLabel} 
            />
          ))}
        </Row>
      </Box>
    </Box>
  );
}


// --- components/ForecastItem.tsx ---
import React from 'react';
import { Stack, Text, Row } from '@ggui-ai/design/primitives';
import type { ForecastItemProps } from './types';

export function ForecastItem({
  day,
  icon,
  high,
  low,
  unitLabel,
}: ForecastItemProps) {
  return (
    <Stack
      align="center"
      gap="var(--ggui-spacing-2)"
      role="listitem"
      aria-label={`${day} forecast`}
      style={{ flex: 1 }}
    >
      <Text variant="label" color="var(--ggui-color-onSurface)">
        {day}
      </Text>
      <Text variant="bodyLarge">{icon}</Text>
      <Row gap="var(--ggui-spacing-1)" justify="center">
        <Text variant="bodySmall" color="var(--ggui-color-onSurface)">
          {high}{unitLabel}
        </Text>
        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
          {low}{unitLabel}
        </Text>
      </Row>
    </Stack>
  );
}


// --- ui.tsx ---
import React from 'react';
import { Card, Stack, Divider } from '@ggui-ai/design/primitives';
import { WeatherHeader, WeatherDetails, ForecastStrip } from './components';
import { useWeatherCard } from './hooks';
import type { WeatherCardProps } from './types';

export const WeatherCard: React.FC<WeatherCardProps> = (props) => {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    forecast,
  } = props;

  const {
    formattedTemp,
    formattedHumidity,
    formattedWind,
    displayCondition,
    weatherEmoji,
    unitLabel,
  } = useWeatherCard({
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    forecast,
    unit: props.unit,
  });

  return (
    <Card padding="var(--ggui-spacing-6)" shadow="md" radius="xl" style={{ maxWidth: '400px', margin: '0 auto' }}>
      <Stack gap="var(--ggui-spacing-6)">
        <WeatherHeader
          city={city}
          temperature={formattedTemp}
          condition={displayCondition}
          emoji={weatherEmoji}
        />
        <WeatherDetails
          humidity={formattedHumidity}
          windSpeed={formattedWind}
        />
        <Divider margin="var(--ggui-spacing-4)" />
        <ForecastStrip
          forecast={forecast}
          unitLabel={unitLabel}
        />
      </Stack>
    </Card>
  );
};


// --- render.tsx ---
// render.tsx — entry point
import React from 'react';
import type { Props } from './types';
import { useComponent } from './hooks';
import { ComponentUI } from './ui';

export default function Component(props: Props) {
  const state = useComponent(props);
  return <ComponentUI {...props} {...state} />;
}
